local xml = require("xml")

function handle_request(ngx)
    local request_body = ngx.req.get_body_data()
    local xml_doc = xml.parse(request_body)

    -- Extract data from parsed XML for processing
    local data = {
        name = xml_doc:find("//name"):text(),
        age = tonumber(xml_doc:find("//age"):text()),
        gender = xml_doc:find("//gender"):text()
    }

    -- Process extracted data
    print(data.name)
    print(data.age)
    print(data.gender)
end